# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 children for lowercase letters a-z
    bool isEndOfWord;

    TrieNode() {
        children.resize(26, nullptr);  // Initialize with 26 null pointers
        isEndOfWord = false;
    }
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    ~Trie() {
        deleteTrie(root);
    }

    // Insert a word into the trie
    void insert(const string& word) {
        TrieNode* node = root;

        for (char c : word) {
            int index = c - 'a';  // Convert character to index (0-25)

            if (node->children[index] == nullptr) {
                node->children[index] = new TrieNode();
            }
            node = node->children[index];
        }

        node->isEndOfWord = true;  // Mark end of word
    }

    // Search for a complete word
    bool search(const string& word) {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Check if there's any word with given prefix
    bool startsWith(const string& prefix) {
        return findNode(prefix) != nullptr;
    }

    // Delete a word from the trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Print all words in the trie
    void printAllWords() {
        string currentWord = "";
        printHelper(root, currentWord);
    }

    // Get all words with a given prefix
    vector<string> getWordsWithPrefix(const string& prefix) {
        vector<string> result;
        TrieNode* node = findNode(prefix);

        if (node == nullptr) {
            return result;
        }

        string currentWord = prefix;
        getWordsHelper(node, currentWord, result);
        return result;
    }

private:
    // Helper function to find a node for a given prefix
    TrieNode* findNode(const string& prefix) {
        TrieNode* node = root;

        for (char c : prefix) {
            int index = c - 'a';

            if (node->children[index] == nullptr) {
                return nullptr;
            }
            node = node->children[index];
        }

        return node;
    }

    // Helper function to delete a word
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word doesn't exist
            }

            node->isEndOfWord = false;

            // Check if node has any children
            for (int i = 0; i < 26; i++) {
                if (node->children[i] != nullptr) {
                    return false;  // Node has children, don't delete
                }
            }

            return true;  // Node can be deleted
        }

        int charIndex = word[index] - 'a';

        if (node->children[charIndex] == nullptr) {
            return false;  // Word doesn't exist
        }

        bool shouldDeleteChild = deleteHelper(node->children[charIndex], 
                                              word, index + 1);

        if (shouldDeleteChild) {
            delete node->children[charIndex];
            node->children[charIndex] = nullptr;

            // Delete current node if it's not end of another word and has no children
            if (!node->isEndOfWord) {
                for (int i = 0; i < 26; i++) {
                    if (node->children[i] != nullptr) {
                        return false;
                    }
                }
                return true;
            }

            return false;
        }

        return false;
    }

    // Helper function to print all words
    void printHelper(TrieNode* node, string& currentWord) {
        if (node->isEndOfWord) {
            cout << currentWord << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                currentWord.push_back('a' + i);
                printHelper(node->children[i], currentWord);
                currentWord.pop_back();
            }
        }
    }

    // Helper function to get words with prefix
    void getWordsHelper(TrieNode* node, string& currentWord, vector<string>& result) {
        if (node->isEndOfWord) {
            result.push_back(currentWord);
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                currentWord.push_back('a' + i);
                getWordsHelper(node->children[i], currentWord, result);
                currentWord.pop_back();
            }
        }
    }

    // Helper function to delete the entire trie
    void deleteTrie(TrieNode* node) {
        if (node == nullptr) {
            return;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                deleteTrie(node->children[i]);
            }
        }

        delete node;
    }
};

// Driver code with test cases
int main() {
    Trie trie;

    // Insert words
    cout << "Inserting words: apple, app, apricot, banana, band" << endl;
    trie.insert("apple");
    trie.insert("app");
    trie.insert("apricot");
    trie.insert("banana");
    trie.insert("band");

    // Search operations
    cout << "\nSearch Results:" << endl;
    cout << "Searching 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Searching 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Searching 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;

    // Prefix search
    cout << "\nPrefix Search Results:" << endl;
    cout << "Prefix 'ap': " << (trie.startsWith("ap") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'ban': " << (trie.startsWith("ban") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'cat': " << (trie.startsWith("cat") ? "Found" : "Not Found") << endl;

    // Get all words with prefix
    cout << "\nWords with prefix 'ap':" << endl;
    vector<string> words = trie.getWordsWithPrefix("ap");
    for (const string& word : words) {
        cout << "  " << word << endl;
    }

    cout << "\nWords with prefix 'ban':" << endl;
    words = trie.getWordsWithPrefix("ban");
    for (const string& word : words) {
        cout << "  " << word << endl;
    }

    // Print all words
    cout << "\nAll words in Trie:" << endl;
    trie.printAllWords();

    // Delete a word
    cout << "\nDeleting 'app'..." << endl;
    trie.deleteWord("app");

    cout << "Searching 'app' after deletion: " 
         << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Searching 'apple' after deletion: " 
         << (trie.search("apple") ? "Found" : "Not Found") << endl;

    return 0;
}
```

## Output:
```
Inserting words: apple, app, apricot, banana, band

Search Results:
Searching 'app': Found
Searching 'apple': Found
Searching 'appl': Not Found

Prefix Search Results:
Prefix 'ap': Found
Prefix 'ban': Found
Prefix 'cat': Not Found

Words with prefix 'ap':
  app
  apple
  apricot

Words with prefix 'ban':
  banana
  band

All words in Trie:
app
apple
apricot
banana
band

Deleting 'app'...
Searching 'app' after deletion: Not Found
Searching 'apple' after deletion: Found
```

## Key Features:

1. **insert()** - O(m) where m is word length
2. **search()** - O(m)
3. **startsWith()** - O(m)
4. **deleteWord()** - O(m)
5. **printAllWords()** - O(n*m) where n is number of words
6. **getWordsWithPrefix()** - Returns all words starting with a prefix

This implementation is efficient and handles all common Trie operations!
